import { describe, expect, it } from "vitest";
import { parseQuery } from "../src/parseQuery.js";

describe("parseQuery", () => {
  describe("basic parsing", () => {
    it("parses a single key=value pair", () => {
      expect(parseQuery("a=1")).toEqual({ a: "1" });
    });

    it("parses multiple distinct keys", () => {
      expect(parseQuery("a=1&b=2&c=3")).toEqual({ a: "1", b: "2", c: "3" });
    });

    it("keeps all values as strings, never coercing to numbers", () => {
      const result = parseQuery("n=42");
      expect(result.n).toBe("42");
      expect(typeof result.n).toBe("string");
    });

    it("returns a plain object", () => {
      const result = parseQuery("a=1");
      expect(typeof result).toBe("object");
      expect(result).not.toBeNull();
      expect(Array.isArray(result)).toBe(false);
    });
  });

  describe("empty and edge inputs", () => {
    it("returns an empty object for an empty string", () => {
      expect(parseQuery("")).toEqual({});
    });

    it("returns an empty object for a lone '?'", () => {
      expect(parseQuery("?")).toEqual({});
    });

    it("returns an empty object for a string of only separators", () => {
      expect(parseQuery("&&&")).toEqual({});
    });
  });

  describe("leading '?' handling", () => {
    it("strips a single leading '?'", () => {
      expect(parseQuery("?a=1")).toEqual({ a: "1" });
    });

    it("parses correctly without a leading '?'", () => {
      expect(parseQuery("a=1")).toEqual({ a: "1" });
    });

    it("strips only one leading '?', treating a second as part of the key", () => {
      // Only the first "?" is removed; the remaining "?a" becomes the key.
      expect(parseQuery("??a=1")).toEqual({ "?a": "1" });
    });

    it("does not strip a '?' that is not at the start", () => {
      expect(parseQuery("a=1?b=2")).toEqual({ a: "1?b=2" });
    });
  });

  describe("empty segments", () => {
    it("skips empty segments between pairs", () => {
      expect(parseQuery("a=1&&b=2")).toEqual({ a: "1", b: "2" });
    });

    it("skips a leading empty segment", () => {
      expect(parseQuery("&a=1")).toEqual({ a: "1" });
    });

    it("skips a trailing empty segment", () => {
      expect(parseQuery("a=1&")).toEqual({ a: "1" });
    });

    it("skips several consecutive empty segments", () => {
      expect(parseQuery("a=1&&&&b=2")).toEqual({ a: "1", b: "2" });
    });
  });

  describe("bare keys (no '=')", () => {
    it("maps a bare key to an empty string", () => {
      expect(parseQuery("flag")).toEqual({ flag: "" });
    });

    it("maps multiple bare keys each to an empty string", () => {
      expect(parseQuery("a&b&c")).toEqual({ a: "", b: "", c: "" });
    });

    it("mixes bare keys and key=value pairs", () => {
      expect(parseQuery("flag&a=1")).toEqual({ flag: "", a: "1" });
    });
  });

  describe("empty keys and values", () => {
    it("maps a key with an empty value to an empty string", () => {
      expect(parseQuery("a=")).toEqual({ a: "" });
    });

    it("handles an empty key with a value", () => {
      expect(parseQuery("=b")).toEqual({ "": "b" });
    });

    it("handles a segment that is just '='", () => {
      expect(parseQuery("=")).toEqual({ "": "" });
    });
  });

  describe("values containing '='", () => {
    it("splits on the first '=' only, keeping the rest in the value", () => {
      expect(parseQuery("a=b=c")).toEqual({ a: "b=c" });
    });

    it("preserves multiple '=' characters in the value", () => {
      expect(parseQuery("eq=1=2=3")).toEqual({ eq: "1=2=3" });
    });

    it("treats a value that starts with '=' as a leading empty segment of the value", () => {
      expect(parseQuery("a==b")).toEqual({ a: "=b" });
    });
  });

  describe("repeated keys", () => {
    it("collects two occurrences of a key into an array", () => {
      expect(parseQuery("a=1&a=2")).toEqual({ a: ["1", "2"] });
    });

    it("collects three or more occurrences into a single array", () => {
      expect(parseQuery("a=1&a=2&a=3")).toEqual({ a: ["1", "2", "3"] });
    });

    it("preserves the order of appearance in the array", () => {
      expect(parseQuery("x=z&x=a&x=m")).toEqual({ x: ["z", "a", "m"] });
    });

    it("keeps a single occurrence as a string, not an array", () => {
      const result = parseQuery("a=1");
      expect(Array.isArray(result.a)).toBe(false);
      expect(result.a).toBe("1");
    });

    it("groups repeated keys independently from other keys", () => {
      expect(parseQuery("a=1&b=2&a=3")).toEqual({ a: ["1", "3"], b: "2" });
    });

    it("arrays include empty-string values from repeated bare/empty keys", () => {
      expect(parseQuery("a&a=1")).toEqual({ a: ["", "1"] });
      expect(parseQuery("a=1&a")).toEqual({ a: ["1", ""] });
      expect(parseQuery("a&a")).toEqual({ a: ["", ""] });
    });
  });

  describe("'+' decoding", () => {
    it("decodes '+' to a space in values", () => {
      expect(parseQuery("a=hello+world")).toEqual({ a: "hello world" });
    });

    it("decodes '+' to a space in keys", () => {
      expect(parseQuery("first+name=jo")).toEqual({ "first name": "jo" });
    });

    it("decodes '+' in both key and value", () => {
      expect(parseQuery("a+b=c+d")).toEqual({ "a b": "c d" });
    });

    it("decodes multiple and consecutive '+' characters", () => {
      expect(parseQuery("a=x++y")).toEqual({ a: "x  y" });
    });
  });

  describe("percent decoding", () => {
    it("percent-decodes a value", () => {
      expect(parseQuery("a=%20")).toEqual({ a: " " });
    });

    it("percent-decodes a key", () => {
      expect(parseQuery("%61=1")).toEqual({ a: "1" });
    });

    it("decodes an encoded ampersand within a value", () => {
      expect(parseQuery("a=1%262")).toEqual({ a: "1&2" });
    });

    it("decodes an encoded equals within a value", () => {
      expect(parseQuery("a=1%3D2")).toEqual({ a: "1=2" });
    });

    it("decodes a literal '+' that was percent-encoded, without turning it into a space", () => {
      // "+" replacement happens first, but "%2B" contains no literal "+",
      // so it survives to be decoded into an actual "+".
      expect(parseQuery("a=%2B")).toEqual({ a: "+" });
    });

    it("decodes multi-byte UTF-8 sequences", () => {
      expect(parseQuery("emoji=%F0%9F%98%80")).toEqual({ emoji: "\u{1F600}" });
    });

    it("applies '+' replacement before percent-decoding", () => {
      expect(parseQuery("a=%23+tag")).toEqual({ a: "# tag" });
    });
  });

  describe("malformed percent sequences (never throws)", () => {
    it("uses the raw token when percent-decoding fails", () => {
      expect(parseQuery("a=%zz")).toEqual({ a: "%zz" });
    });

    it("handles a lone trailing '%'", () => {
      expect(parseQuery("a=%")).toEqual({ a: "%" });
    });

    it("handles a truncated percent sequence", () => {
      expect(parseQuery("a=%E0%A4")).toEqual({ a: "%E0%A4" });
    });

    it("falls back to the '+'-replaced token when decoding fails", () => {
      // "+" is replaced with a space first; then decodeURIComponent("% ")
      // throws, so the already-'+'-replaced token "% " is returned as-is.
      expect(parseQuery("a=%+")).toEqual({ a: "% " });
    });

    it("uses the raw token for a malformed key", () => {
      expect(parseQuery("%zz=1")).toEqual({ "%zz": "1" });
    });

    it("does not throw for a variety of malformed inputs", () => {
      const malformed = ["a=%", "%", "a=%2", "=%zz", "%gg=%hh", "a=%C3%28"];
      for (const input of malformed) {
        expect(() => parseQuery(input)).not.toThrow();
      }
    });
  });

  describe("combined scenarios", () => {
    it("handles a realistic mixed query string", () => {
      expect(
        parseQuery("?name=John+Doe&age=30&tag=a&tag=b&flag&note=%3Chi%3E")
      ).toEqual({
        name: "John Doe",
        age: "30",
        tag: ["a", "b"],
        flag: "",
        note: "<hi>",
      });
    });

    it("combines empty segments, repeats, and encoding", () => {
      expect(parseQuery("&a=1&&a=%20&a=x+y&")).toEqual({
        a: ["1", " ", "x y"],
      });
    });
  });
});

